import React, {useCallback, useMemo, useRef, useState} from "react";
import axios from "axios";
import Experian from "./Experian";
import type {IKitsInputLocation, ILocationDetailsResponse, ILocationResponse, IRef} from "@lmb-it/kitsconcerto-types";
import {FormSelect} from "../../../";

const GOOGLE_AUTOCOMPLETE =
    "https://maps.googleapis.com/maps/api/place/autocomplete/json";
const GOOGLE_DETAILS =
    "https://maps.googleapis.com/maps/api/place/details/json";

type Suggestion = {
    label: string;
    value: string;
    format?: string;
};

const KitsInputLocation = ({
                               id,
                               label,
                               errors,
                               invalid,
                               value,
                               hideError,
                               onAddressClick,
                               onChange,
                               disabled,
                               placeholder,
                               countryISO = "AUS",
                               helperText,
                               provider,
                               api_key,
                               labelKey = "label",
                               valueKey = "value",
                               list,
                               ...rest
                           }: IKitsInputLocation) => {
    if (!api_key) throw new Error("API KEY NOT PROVIDED");

    const selectRef = useRef<IRef>(null);
    const [suggestions, setSuggestions] = useState<Suggestion[]>([]);

    const experian = useMemo(
        () => (provider !== "google" ? new Experian(api_key) : null),
        [provider, api_key]
    );

    const search = useCallback(
        async (query: string): Promise<Suggestion[]> => {
            if (query.length < 4) return [];

            try {
                if (provider === "google") {
                    let url = `${GOOGLE_AUTOCOMPLETE}?input=${encodeURIComponent(
                        query
                    )}&key=${api_key}`;
                    if (countryISO) {
                        url += `&components=country:${countryISO.toLowerCase().slice(0, 2)}`;
                    }
                    const {data} = await axios.get<ILocationResponse>(url);

                    const mapped = data.predictions?.map((p) => ({
                        label: p.description,
                        value: p.place_id,
                    })) || [];
                    setSuggestions(mapped);
                    return mapped;
                } else {
                    const res = await experian?.searchAddress(query, countryISO);
                    const mapped = res?.data?.result?.suggestions?.map((s: any) => ({
                        label: s.text,
                        value: s.global_address_key,
                        format: s.format,
                    })) || [];
                    setSuggestions(mapped);
                    return mapped;
                }
            } catch {
                setSuggestions([]);
                return [];
            }
        },
        [provider, api_key, countryISO, experian]
    );

    const onPickAddress = useCallback(
        async (event: any, rawItem?: any) => {
            // rawItem is the full suggestion { label, value } passed as second arg by the hook
            const selected = rawItem ?? event;
            if (!selected) return;

            const placeId = selected[valueKey];

            onChange?.({
                target: {value: selected[labelKey]},
            } as any);

            if (!onAddressClick || !placeId) return;

            if (provider === "google") {
                const {data} = await axios.get<ILocationDetailsResponse>(
                    `${GOOGLE_DETAILS}?place_id=${placeId}&key=${api_key}`
                );

                const address: Record<string, string> = {
                    formatted_address: data.result.formatted_address,
                };

                data.result.address_components.forEach((c) => {
                    const type = c?.types?.[0]; // Safely get the first type or undefined

                    if (type && type in address) {
                        // Use 'as keyof typeof address' if TypeScript complains about the index signature
                        address[type as keyof typeof address] = c.long_name;
                    }
                });

                onAddressClick(address);
            } else {
                const res = await experian?.formatAddress(placeId);
                if (res?.data?.result) { // @ts-ignore
                    onAddressClick(res.data.result);
                }
            }
        },
        [
            provider,
            api_key,
            valueKey,
            labelKey,
            onChange,
            onAddressClick,
            experian,
        ]
    );

    return (
        <FormSelect
            ref={selectRef}
            id={id}
            shape="autocomplete"
            value={value}
            label={label}
            placeholder={placeholder}
            labelKey={labelKey}
            valueKey={valueKey}
            onChange={onPickAddress}
            isMultiple={false}
            forceSelection
            completeMethod={search}
            list={suggestions}
            helperText={helperText}
            hideError={hideError}
            disabled={disabled}
            invalid={invalid}
            errors={errors}
            {...rest}
        />
    );
};

export default KitsInputLocation;
